            azure_openai_api_version?: string | null;
            /** @description Azure OpenAI deployment name — the deployment you created in Azure AI Studio that wraps a specific model. Azure-only; ignore for other providers. */
            azure_openai_deployment?: string | null;
            /** @description Azure OpenAI resource name (the `<resource>` part of `<resource>.openai.azure.com`). Azure-only; ignore for OpenAI, Anthropic, and everything else. */
            azure_openai_resource?: string | null;
            /** @description HTTPS endpoint the client hits. Override when pointing at a self-hosted gateway (LiteLLM, vLLM, Ollama), a regional endpoint, or a proxy; leave unset to use the provider's public endpoint. */
            base_url?: string | null;
